fun main() {
    // ---- Data class destructuring ----
    data class Person(val name: String, val age: Int, val city: String)
    val person = Person("Alice", 25, "New York")

    // Destructure
    val (name, age, city) = person
    println("Name: $name, Age: $age, City: $city")

    // ---- Ignoring values ----
    val (name2, _, city2) = Person("Bob", 30, "London")
    println("Name: $name2, City: $city2")

    // ---- List destructuring ----
    val numbers = listOf(1, 2, 3, 4, 5)
    val (first, second, third) = numbers
    println("First: $first, Second: $second, Third: $third")

    // ---- Pair destructuring ----
    val pair = "Alice" to 25
    val (name3, age3) = pair
    println("Name: $name3, Age: $age3")

    // ---- Triple destructuring ----
    val triple = Triple("Bob", 30, "London")
    val (name4, age4, city4) = triple
    println("Name: $name4, Age: $age4, City: $city4")

    // ---- Map destructuring ----
    val map = mapOf(
        "Alice" to 25,
        "Bob" to 30,
        "Charlie" to 35
    )

    for ((key, value) in map) {
        println("$key is $value years old")
    }

    // ---- Custom destructuring ----
    class Point(val x: Int, val y: Int) {
        // Component functions required for destructuring
        operator fun component1() = x
        operator fun component2() = y
    }

    val point = Point(10, 20)
    val (x, y) = point
    println("Point: ($x, $y)")

    // ---- Destructuring in lambdas ----
    data class User(val name: String, val age: Int)
    val users = listOf(
        User("Alice", 25),
        User("Bob", 30),
        User("Charlie", 35)
    )

    users.forEach { (name, age) ->
        println("$name is $age years old")
    }

    // ---- Destructuring with filter and map ----
    users
        .filter { (_, age) -> age >= 30 }
        .map { (name, _) -> name }
        .forEach { println("Adult: $it") }

    // ---- Nested destructuring ----
    data class Address(val city: String, val country: String)
    data class Employee(val name: String, val address: Address)

    val employee = Employee("Alice", Address("New York", "USA"))
    val (empName, address) = employee
    val (empCity, empCountry) = address
    println("$empName lives in $empCity, $empCountry")

    // ---- Destructuring in function returns ----
    fun getUserInfo(): Pair<String, Int> {
        return "Alice" to 25
    }

    val (name5, age5) = getUserInfo()
    println("Name: $name5, Age: $age5")
}

