phase3.solution:
data class Employee(val name: String, val age: Int, val department: String)

fun main() {
    val employees = listOf(
        Employee("Alice", 25, "Engineering"),
        Employee("Bob", 30, "Engineering"),
        Employee("Charlie", 35, "Sales"),
        Employee("Diana", 28, "Marketing")
    )

    // Loop with destructuring
    println("All employees:")
    for ((name, age, dept) in employees) {
        println("$name ($age) - $dept")
    }

    // Filter with destructuring
    val engineers = employees.filter { (_, _, dept) -> dept == "Engineering" }
    println("\nEngineers: $engineers")

    // Map with destructuring
    val names = engineers.map { (name, _, _) -> name }
    println("\nEngineer names: $names")
}
